import React, { useState, useEffect } from 'react';
import Login from './pages/Login.js';
import BuyerDash from './pages/BuyerDash.js';
import SellerDash from './pages/SellerDash.js';

function App() {
  const [user, setUser] = useState(null);

  // Check LocalStorage on load to see if someone is already logged in
  useEffect(() => {
    const savedUser = localStorage.getItem('agriUser');
    if (savedUser) setUser(JSON.parse(savedUser));
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('agriUser');
    setUser(null);
  };

  if (!user) {
    return <Login onLogin={setUser} />;
  }

  return (
    <div>
      <nav style={{ padding: '10px', background: '#2d5a27', color: 'white', display: 'flex', justifyContent: 'space-between' }}>
        <span>🌱 Agri-AI Platform ({user.role})</span>
        <button onClick={handleLogout} style={{ background: 'red', color: 'white', border: 'none', cursor: 'pointer' }}>Logout</button>
      </nav>

      {user.role === 'buyer' ? <BuyerDash /> : <SellerDash />}
    </div>
  );
}

export default App;
